75	void merge_for_sort(std::vector<int>& items_to_sort, int left, int mid, int right) {
76	    int n1 = mid - left + 1;
77	    int n2 = right - mid;
78	    std::vector<int> L_half(n1), R_half(n2);
79	    for (int i = 0; i < n1; i++) L_half[i] = items_to_sort[left + i];
80	    for (int j = 0; j < n2; j++) R_half[j] = items_to_sort[mid + 1 + j];
81	    int i = 0, j = 0, k = left;
82	    while (i < n1 && j < n2) {
83	        char cmp_res = compare_single_items(L_half[i], R_half[j]);
84	        if (cmp_res == '<' || cmp_res == '=') {
85	            items_to_sort[k++] = L_half[i++];
86	        } else {
87	            items_to_sort[k++] = R_half[j++];
88	        }
89	    }
90	    while (i < n1) items_to_sort[k++] = L_half[i++];
91	    while (j < n2) items_to_sort[k++] = R_half[j++];
92	}
