110	int calculate_estimated_query_cost(int N_val, int k_pivots_val) {
111	    if (k_pivots_val <= 0) return 0;
112	    if (k_pivots_val == 1) return (N_val > 1) ? (N_val - 1) : 0;
113	    double cost = 0;
114	    cost += static_cast<double>(k_pivots_val) * estimate_log2(static_cast<double>(k_pivots_val));
115	    for (int j = 2; j < k_pivots_val; ++j) {
116	        if (j - 1 > 0) cost += estimate_log2(static_cast<double>(j - 1));
117	    }
118	    cost += static_cast<double>(N_val - k_pivots_val) * estimate_log2(static_cast<double>(k_pivots_val));
119	    return static_cast<int>(std::ceil(cost));
120	}
