// 3. Binary search within the heavy group to find the best item to move
if (queries_made < Q_total_global && D_groups_global > 1) {
    int consecutive_no_improve = 0;

    while (queries_made < Q_total_global) {
        auto time_now = std::chrono::steady_clock::now();
        if (std::chrono::duration_cast<std::chrono::milliseconds>(time_now - program_start_time) >= time_limit_ms) break;

        int queries_left = Q_total_global - queries_made;
        if (queries_left < 2 * (D_groups_global - 1) + 1) break;

        // Find heaviest group via tournament
        int heaviest_grp = -1;
        for (int g = 0; g < D_groups_global; g++) {
            if (group_items_indices[g].empty()) continue;
            if (heaviest_grp == -1) { heaviest_grp = g; continue; }
            if (queries_made >= Q_total_global) break;
            char res = compare_groups(group_items_indices[heaviest_grp], group_items_indices[g]);
            if (res == '<') heaviest_grp = g;
        }
        if (heaviest_grp == -1) break;

        // Find lightest group via tournament
        int lightest_grp = -1;
        for (int g = 0; g < D_groups_global; g++) {
            if (g == heaviest_grp) continue;
            if (group_items_indices[g].empty()) continue;
            if (lightest_grp == -1) { lightest_grp = g; continue; }
            if (queries_made >= Q_total_global) break;
            char res = compare_groups(group_items_indices[lightest_grp], group_items_indices[g]);
            if (res == '>') lightest_grp = g;
        }
        if (lightest_grp == -1 || lightest_grp == heaviest_grp) break;

        // Confirm heavy > light
        if (queries_made >= Q_total_global) break;
        char confirm = compare_groups(group_items_indices[heaviest_grp], group_items_indices[lightest_grp]);
        if (confirm != '>') {
            consecutive_no_improve++;
            if (consecutive_no_improve > 3) break;
            continue;
        }
        consecutive_no_improve = 0;

        // Pick item to move: closest to half the estimated gap
        long long target_diff = (group_sums_array[heaviest_grp] - group_sums_array[lightest_grp]) / 2;

        int best_move_item = -1;
        long long best_move_err = LLONG_MAX;
        for (int ih : group_items_indices[heaviest_grp]) {
            long long err = std::abs(estimated_weights[ih] - target_diff);
            if (err < best_move_err) {
                best_move_err = err;
                best_move_item = ih;
            }
        }

        if (best_move_item == -1) break;

        // Check overshoot with ground truth comparison
        bool do_move = true;
        if (queries_made < Q_total_global && group_items_indices[heaviest_grp].size() > 1) {
            std::vector<int> heavy_minus_item;
            for (int ih : group_items_indices[heaviest_grp]) {
                if (ih != best_move_item) heavy_minus_item.push_back(ih);
            }
            std::vector<int> light_plus_item = group_items_indices[lightest_grp];
            light_plus_item.push_back(best_move_item);

            char after_move = compare_groups(heavy_minus_item, light_plus_item);
            if (after_move == '<') {
                // Overshoot! Try swap: smallest from heavy with largest from light
                int smallest_in_heavy = -1;
                long long smallest_w = LLONG_MAX;
                for (int ih : group_items_indices[heaviest_grp]) {
                    if (estimated_weights[ih] < smallest_w) {
                        smallest_w = estimated_weights[ih];
                        smallest_in_heavy = ih;
                    }
                }
                int largest_in_light = -1;
                long long largest_w = 0;
                for (int il : group_items_indices[lightest_grp]) {
                    if (estimated_weights[il] > largest_w) {
                        largest_w = estimated_weights[il];
                        largest_in_light = il;
                    }
                }

                if (smallest_in_heavy != -1 && largest_in_light != -1 &&
                    estimated_weights[smallest_in_heavy] > estimated_weights[largest_in_light]) {
                    long long sw1 = estimated_weights[smallest_in_heavy];
                    long long sw2 = estimated_weights[largest_in_light];
                    group_sums_array[heaviest_grp] -= sw1;
                    group_sums_array[heaviest_grp] += sw2;
                    group_sums_array[lightest_grp] -= sw2;
                    group_sums_array[lightest_grp] += sw1;

                    assignment_array[smallest_in_heavy] = lightest_grp;
                    assignment_array[largest_in_light] = heaviest_grp;

                    int pos1 = item_pos_in_group_vector[smallest_in_heavy];
                    int back1 = group_items_indices[heaviest_grp].back();
                    if (smallest_in_heavy != back1) {
                        group_items_indices[heaviest_grp][pos1] = back1;
                        item_pos_in_group_vector[back1] = pos1;
                    }
                    group_items_indices[heaviest_grp].pop_back();

                    int pos2 = item_pos_in_group_vector[largest_in_light];
                    int back2 = group_items_indices[lightest_grp].back();
                    if (largest_in_light != back2) {
                        group_items_indices[lightest_grp][pos2] = back2;
                        item_pos_in_group_vector[back2] = pos2;
                    }
                    group_items_indices[lightest_grp].pop_back();

                    group_items_indices[lightest_grp].push_back(smallest_in_heavy);
                    item_pos_in_group_vector[smallest_in_heavy] = group_items_indices[lightest_grp].size() - 1;
                    group_items_indices[heaviest_grp].push_back(largest_in_light);
                    item_pos_in_group_vector[largest_in_light] = group_items_indices[heaviest_grp].size() - 1;

                    do_move = false;
                } else {
                    // Move smallest item instead
                    if (smallest_in_heavy != -1) {
                        best_move_item = smallest_in_heavy;
                    } else {
                        do_move = false;
                    }
                }
            }
            // If after_move == '=' or '>', the move is good or perfect
        }

        if (do_move) {
            long long item_w = estimated_weights[best_move_item];
            group_sums_array[heaviest_grp] -= item_w;
            group_sums_array[lightest_grp] += item_w;
            assignment_array[best_move_item] = lightest_grp;

            int pos = item_pos_in_group_vector[best_move_item];
            int last_item = group_items_indices[heaviest_grp].back();
            if (best_move_item != last_item) {
                group_items_indices[heaviest_grp][pos] = last_item;
                item_pos_in_group_vector[last_item] = pos;
            }
            group_items_indices[heaviest_grp].pop_back();
            group_items_indices[lightest_grp].push_back(best_move_item);
            item_pos_in_group_vector[best_move_item] = group_items_indices[lightest_grp].size() - 1;
        }
    }
}

// Exhaust any remaining queries
while (queries_made < Q_total_global) {
    perform_query_actual({0}, {1});
}

for (int i = 0; i < N_items_global; ++i) {
    std::cout << assignment_array[i] << (i == N_items_global - 1 ? "" : " ");
}
std::cout << std::endl;

return 0;

